### 1. EventEnvelope Unit Tests

```rust
#[cfg(test)]
mod event_envelope_tests {
    use fcp_sdk::streaming::{EventEnvelope, EventCaps};
    use fcp_cbor::{CanonicalSerializer, SchemaId};
    use semver::Version;

    #[test]
    fn test_envelope_canonical_encoding() {
        let envelope = EventEnvelope {
            topic: "user.created".into(),
            timestamp: 1706745600000,
            seq: 42,
            cursor: "cursor_abc123".into(),
            requires_ack: true,
            data: serde_json::json\!({"user_id": "u_123", "email": "test@example.com"}),
        };

        let schema = SchemaId::new("fcp.sdk", "EventEnvelope", Version::new(2, 0, 0));
        let bytes = CanonicalSerializer::serialize(&envelope, &schema).unwrap();

        // Verify deterministic encoding (same input -> same bytes)
        let bytes2 = CanonicalSerializer::serialize(&envelope, &schema).unwrap();
        assert_eq\!(bytes, bytes2, "canonical encoding must be deterministic");

        // Verify round-trip
        let decoded: EventEnvelope = CanonicalSerializer::deserialize(&bytes, &schema).unwrap();
        assert_eq\!(decoded.topic, envelope.topic);
        assert_eq\!(decoded.cursor, envelope.cursor);
    }

    #[test]
    fn test_cursor_monotonicity() {
        let mut prev_seq = 0u64;
        for i in 1..=1000 {
            let envelope = EventEnvelope::new("test.topic", i, format\!("cursor_{i}"));
            assert\!(envelope.seq > prev_seq, "sequence must be monotonically increasing");
            prev_seq = envelope.seq;
        }
    }

    #[test]
    fn test_ack_required_flag_preservation() {
        // When requires_ack=true, the envelope MUST preserve this across serialization
        let envelope = EventEnvelope::builder()
            .topic("critical.event")
            .requires_ack(true)
            .build();

        let bytes = envelope.to_canonical_bytes().unwrap();
        let decoded = EventEnvelope::from_canonical_bytes(&bytes).unwrap();
        assert\!(decoded.requires_ack, "requires_ack must survive round-trip");
    }

    #[test]
    fn test_envelope_timestamp_nanosecond_precision() {
        let now_ns = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_nanos() as u64;

        let envelope = EventEnvelope::with_timestamp("test.topic", now_ns);
        assert_eq\!(envelope.timestamp, now_ns);
    }
}
