### 2. Replay Semantics Tests

```rust
#[cfg(test)]
mod replay_tests {
    use fcp_sdk::streaming::{StreamingConnector, ReplayBuffer, Cursor};

    #[test]
    fn test_replay_from_cursor_exact() {
        let buffer = ReplayBuffer::new(100);

        // Emit 50 events
        for i in 1..=50 {
            buffer.push(EventEnvelope::new("test", i, format\!("c{i}")));
        }

        // Replay from cursor c25
        let replayed: Vec<_> = buffer.replay_from(Cursor::parse("c25").unwrap()).collect();
        assert_eq\!(replayed.len(), 25); // Events 26-50
        assert_eq\!(replayed[0].seq, 26);
        assert_eq\!(replayed[24].seq, 50);
    }

    #[test]
    fn test_replay_cursor_not_found_returns_earliest() {
        let buffer = ReplayBuffer::new(100);

        // Emit events 50-100 (cursor c1-c49 already evicted)
        for i in 50..=100 {
            buffer.push(EventEnvelope::new("test", i, format\!("c{i}")));
        }

        // Request replay from evicted cursor
        let replayed: Vec<_> = buffer.replay_from(Cursor::parse("c10").unwrap()).collect();
        // Should return from earliest available (c50)
        assert_eq\!(replayed[0].cursor, "c50");
    }

    #[test]
    fn test_replay_buffer_eviction_fifo() {
        let buffer = ReplayBuffer::new(10); // Only 10 events

        // Push 20 events
        for i in 1..=20 {
            buffer.push(EventEnvelope::new("test", i, format\!("c{i}")));
        }

        // Buffer should only have events 11-20
        assert_eq\!(buffer.len(), 10);
        assert_eq\!(buffer.earliest().unwrap().seq, 11);
        assert_eq\!(buffer.latest().unwrap().seq, 20);
    }

    #[test]
    fn test_event_caps_replay_declared() {
        let caps = EventCaps {
            replay: true,
            min_buffer_events: 1000,
            ack_required: false,
        };

        // Connector must honor declared capabilities
        let connector = MockStreamingConnector::with_caps(caps);
        assert\!(connector.supports_replay());
        assert\!(connector.buffer_size() >= 1000);
    }
}
