### 4. Integration Tests (Host<->Connector)

```rust
#[cfg(test)]
mod streaming_integration_tests {
    use fcp_test_harness::{IntegrationHarness, MockHost, StreamingConnector};

    #[tokio::test]
    async fn test_subscribe_receive_ack_cycle() {
        let harness = IntegrationHarness::new().await;
        let host = harness.mock_host();
        let connector = harness.streaming_connector("mock-streaming");

        // 1. Subscribe to topic
        let subscription = host.subscribe(connector.id(), "user.events").await?;

        // 2. Trigger events in connector
        connector.emit_event("user.created", json\!({"id": "u1"})).await;
        connector.emit_event("user.updated", json\!({"id": "u1", "name": "Alice"})).await;

        // 3. Receive events
        let events = subscription.recv_batch(2, Duration::from_secs(5)).await?;
        assert_eq\!(events.len(), 2);

        // 4. Ack events
        for event in &events {
            if event.requires_ack {
                host.ack(connector.id(), &event.cursor).await?;
            }
        }

        // 5. Verify ack state
        assert_eq\!(connector.pending_acks(), 0);
    }

    #[tokio::test]
    async fn test_replay_from_cursor_integration() {
        let harness = IntegrationHarness::new().await;
        let host = harness.mock_host();
        let connector = harness.streaming_connector("mock-streaming");

        // Emit 100 events
        for i in 1..=100 {
            connector.emit_event("test.event", json\!({"seq": i})).await;
        }

        // Subscribe with replay from event 50
        let subscription = host.subscribe_with_cursor(
            connector.id(),
            "test.event",
            Cursor::parse("cursor_50").unwrap(),
        ).await?;

        // Should receive events 51-100
        let events = subscription.recv_all(Duration::from_secs(5)).await?;
        assert_eq\!(events.len(), 50);
        assert_eq\!(events[0].data["seq"], 51);
    }

    #[tokio::test]
    async fn test_unacked_event_redelivery() {
        let harness = IntegrationHarness::with_ack_timeout(Duration::from_millis(200)).await;
        let host = harness.mock_host();
        let connector = harness.streaming_connector("mock-streaming");

        // Emit event requiring ack
        connector.emit_event_with_ack("critical.event", json\!({"id": 1})).await;

        // Subscribe and receive
        let subscription = host.subscribe(connector.id(), "critical.event").await?;
        let event = subscription.recv_one(Duration::from_secs(1)).await?;
        assert\!(event.requires_ack);

        // Don't ack - wait for redelivery
        std::thread::sleep(Duration::from_millis(300));

        // Should receive redelivered event
        let redelivered = subscription.recv_one(Duration::from_secs(1)).await?;
        assert_eq\!(redelivered.cursor, event.cursor);
    }
}
