### 3. Preflight Tests

```rust
#[cfg(test)]
mod preflight_tests {
    #[tokio::test]
    async fn test_preflight_checks_authz_without_execution() {
        let host = TestHost::new().await;
        host.install_connector("test-echo").await;

        // No capability token
        let request = PreflightRequest {
            connector_id: ConnectorId::new("test-echo"),
            operation: "echo",
            capability_token: None,
        };

        let result = host.preflight(request).await;

        assert!(!result.allowed);
        assert_eq!(result.reason_code, "FCP-2001"); // No capability token
        // Operation should NOT have been executed
        assert_eq!(host.invocation_count("test-echo"), 0);
    }

    #[tokio::test]
    async fn test_preflight_with_valid_token() {
        let host = TestHost::new().await;
        host.install_connector("test-echo").await;
        let token = host.issue_capability_token("test-echo", vec!["echo"]).await;

        let request = PreflightRequest {
            connector_id: ConnectorId::new("test-echo"),
            operation: "echo",
            capability_token: Some(token),
        };

        let result = host.preflight(request).await;

        assert!(result.allowed);
        assert!(result.reason_code.is_none());
    }

    #[tokio::test]
    async fn test_preflight_expired_token() {
        let host = TestHost::new().await;
        host.install_connector("test-echo").await;
        let expired_token = host.issue_expired_capability_token("test-echo", vec!["echo"]).await;

        let request = PreflightRequest {
            connector_id: ConnectorId::new("test-echo"),
            operation: "echo",
            capability_token: Some(expired_token),
        };

        let result = host.preflight(request).await;

        assert!(!result.allowed);
        assert_eq!(result.reason_code, "FCP-2102"); // Token expired
    }
}
